import sys
from itertools import product

def main():
    N = int(sys.stdin.readline())
    max_len = 1000
    digits = '123456789'
    ops = ['*', '+', '-']  # Only * is valid for multiplication

    # Try all possible palindromic expressions
    for length in range(1, max_len + 1):
        # Generate all possible palindromic expressions with length
        for parts in product(digits, repeat=length // 2):
            # Construct the first half
            first_half = ''.join(parts)
            # Construct the full palindrome
            if length % 2 == 0:
                expr = first_half + first_half[::-1]
            else:
                expr = first_half + parts[-1] + first_half[::-1]
            # Check if the first character is a digit
            if not expr[0].isdigit():
                continue
            # Evaluate the expression
            try:
                value = eval(expr)
                if value == N:
                    print(expr)
                    return
            except:
                continue

    print(-1)

if __name__ == "__main__":
    main()
